// Apollo POSTs: { people:[ { id, phone_numbers:[ { sanitized_number, raw_number, type_cd, status_cd, position } ] } ] }
const b = ($json && $json.body) ? $json.body : $json;
let people = [];
if (Array.isArray(b)) people = b;
else if (Array.isArray(b.people)) people = b.people;
else if (Array.isArray(b.matches)) people = b.matches;
else if (Array.isArray(b.contacts)) people = b.contacts;
else if (b.person) people = [b.person];
else if (b.id || b.phone_numbers) people = [b];
function pick(p){ const a=p.phone_numbers||p.phones||[]; if(Array.isArray(a)&&a.length){ const sc=x=>{const t=String(x.type_cd||x.type||'').toLowerCase();let s=0;if(/mobile|cell/.test(t))s+=100;if(String(x.status_cd||'').toLowerCase().includes('valid'))s+=10;s-=Number(x.position)||0;return s;}; const best=a.slice().sort((x,y)=>sc(y)-sc(x))[0]; const all=a.map(x=>x.sanitized_number||x.raw_number||'').filter(Boolean).join(', '); return {num:best.sanitized_number||best.raw_number||best.number||'',type:best.type_cd||best.type||'',status:best.status_cd||best.status||'',all}; } return {num:p.sanitized_phone||p.phone_number||p.phone||'',type:'',status:'',all:''}; }
const out=[];
for(const p of people){ const id=p.id||p.person_id||''; const ph=pick(p); if(!id||!ph.num) continue; out.push({json:{apollo_id:String(id),phone:ph.num,phone_type:ph.type,phone_status:ph.status,phone_all:ph.all}}); }
return out;

const ph = $('Parse callback').item.json;
const mapRes = $json || {};
const slug = (mapRes.fields && mapRes.fields.slug && mapRes.fields.slug.stringValue) || '';
const S = v => ({ stringValue: (v == null ? '' : String(v)) });
const fsBody = { fields: { phone: S(ph.phone), phone_type: S(ph.phone_type), phone_status: S(ph.phone_status), phone_all: S(ph.phone_all), phone_revealed_at: { timestampValue: new Date().toISOString() } } };
return [{ json: { slug, fsBody, ok: !!(slug && ph.phone) } }];
